mapper.select:
SELECT id, product_id as productId, stock, seckill_stock as seckillStock, create_time as createTime, update_time as updateTime
FROM inventory
WHERE product_id = #{productId}

mapper.update:
UPDATE inventory
SET stock = stock - #{quantity}, update_time = NOW()
WHERE product_id = #{productId} AND stock >= #{quantity}

UPDATE inventory
SET stock = #{stock}, update_time = NOW()
WHERE product_id = #{productId}
